                ttsrv.writeTxtFile("liebiao.json", JSON.stringify(updatedList, null, 2));
                ttsrv.writeTxtFile("cunfang.txt", newBookName);
                ttsrv.writeTxtFile("characterRecords.json", bookData);
                initBookSpinner();
                Toast.makeText(ctx, "已将「" + currentBook + "」重命名为「" + newBookName + "」", Toast.LENGTH_SHORT).show();
