            // 逐个处理标记的角色（倒序避免索引混乱）
            var processQueue = markedIndices.slice().sort(function(a, b) { return b - a; });

            function processNext() {
                if (processQueue.length === 0) {
                    // 全部处理完，保存刷新
                    saveCharacterData();
