            backupOriginalData();

            try {
                // 筛选保留未标记角色
                var newCharacterRecords = [];
                for (var i = 0; i < characterRecords.length; i++) {
                    if (markedIndices.indexOf(i) === -1) {
                        newCharacterRecords.push(characterRecords[i]);
                    }
                }

                characterRecords = newCharacterRecords;

                // 保存并刷新
                saveCharacterData();
                createGengxinFile();

                Toast.makeText(ctx, "已删除" + markedIndices.length + "个角色", Toast.LENGTH_SHORT).show();
                refreshCharacterList();

            } catch (e) {
                console.error("删除角色失败: " + e.toString());
                Toast.makeText(ctx, "操作失败: " + e.toString(), Toast.LENGTH_SHORT).show();
            }
        }

        // 刷新角色列表（更新UI显示）
        function refreshCharacterList(keyword) {
            try {
                adapter.setNotifyOnChange(false);
                adapter.clear();
                filteredIndices = [];
                for (var i = 0; i < characterRecords.length; i++) {
                    var record = characterRecords[i];
                    if (!record) continue;
                    if (keyword) {
                        var charName = (record.name || "").toLowerCase();
                        var charAlias = (record.aliases || "").toLowerCase();
                        var charGender = (record.gender || "").toLowerCase();
                        var charAge = (record.age || "").toLowerCase();
                        var charVoice = (record.voice || "").toLowerCase();
                        var matched = charName.indexOf(keyword) !== -1 ||
                                      charAlias.indexOf(keyword) !== -1 ||
                                      charGender.indexOf(keyword) !== -1 ||
                                      charAge.indexOf(keyword) !== -1 ||
                                      charVoice.indexOf(keyword) !== -1;
                        if (!matched) {
                            continue;
                        }
                    }
                    var displayText = generateDisplayText(record);
                    adapter.add(displayText);
                    filteredIndices.push(i);
                }
                adapter.setNotifyOnChange(true);
                adapter.notifyDataSetChanged();
                markedIndices = [];
                selectedIndex = -1;
                mergeListView.clearChoices();
                updateListViewAppearance();
                mergeLabel.setText("角色列表:");
                if (selectAllBtn) {
                    selectAllBtn.setText("全选");
                    var allShape2 = new android.graphics.drawable.GradientDrawable();
                    allShape2.setShape(android.graphics.drawable.GradientDrawable.RECTANGLE);
                    allShape2.setCornerRadius(dipToPx(6));
                    allShape2.setColor(android.graphics.Color.parseColor("#4CAF50"));
                    selectAllBtn.setBackground(allShape2);
                }
                updateListViewHeight();
            } catch (e) {
                console.error("refreshCharacterList 异常: " + e.toString());
                Toast.makeText(ctx, "列表刷新异常: " + e.toString(), Toast.LENGTH_SHORT).show();
            }
        }

        // 更新列表外观（标记/选中状态可视化）

                function createRoundedDrawable(color, strokeColor) {
            var d = new android.graphics.drawable.GradientDrawable();
            d.setShape(android.graphics.drawable.GradientDrawable.RECTANGLE);
            d.setCornerRadius(dipToPx(8));
            d.setColor(android.graphics.Color.parseColor(color));
            if (strokeColor) d.setStroke(1, android.graphics.Color.parseColor(strokeColor));
            return d;
        }

        // 修复后：直接通过已知布局获取系统颜色，避免遍历查找失败
        function updateListViewAppearance() {
            var systemTextColor = android.graphics.Color.parseColor("#333333");
            try {
                if (bookNameEditor && bookNameEditor instanceof android.widget.EditText) {
                    systemTextColor = bookNameEditor.getCurrentTextColor();
                    console.log("成功获取系统颜色：" + systemTextColor);
                }
            } catch (e) {
                console.error("获取系统颜色失败（将用默认色）：" + e.toString());
            }

            if (mergeLabel && mergeLabel instanceof android.widget.TextView) {
                mergeLabel.setTextColor(systemTextColor);
            }

            var firstVisible = mergeListView.getFirstVisiblePosition();
            for (var i = 0; i < mergeListView.getChildCount(); i++) {
                var child = mergeListView.getChildAt(i);
                var position = firstVisible + i;
                if (child instanceof android.widget.CheckedTextView && position < filteredIndices.length) {
                    var originalIndex = filteredIndices[position];
                    child.setTextColor(systemTextColor);

                    var bgDrawable = createRoundedDrawable("#FFFFFF", "#E0E0E0");

                    if (markedIndices.indexOf(originalIndex) !== -1 && originalIndex !== selectedIndex) {
                        bgDrawable = createRoundedDrawable("#FFF9C4", "#FBC02D");
                        child.setTextColor(android.graphics.Color.parseColor("#333333"));
                    } else if (markedIndices.indexOf(originalIndex) !== -1 && originalIndex === selectedIndex) {
                        bgDrawable = createRoundedDrawable("#FFF9C4", "#FBC02D");
                        child.setTextColor(android.graphics.Color.parseColor("#FF5722"));
                    } else if (originalIndex === selectedIndex) {
                        bgDrawable = createRoundedDrawable("#E3F2FD", "#1976D2");
                        child.setTextColor(android.graphics.Color.parseColor("#1976D2"));
                    }
                    child.setBackground(bgDrawable);
                    child.setPadding(dipToPx(12), dipToPx(8), dipToPx(12), dipToPx(8));
                }
            }
        }


        // 更新列表高度（适配角色数量）
        function updateListViewHeight() {
            var itemHeight = Math.floor(56 * density + 0.5);
            var maxHeight = Math.floor(300000 * density + 0.5);
            var calculatedHeight = Math.min(itemHeight * filteredIndices.length, maxHeight);

            var layoutParams = new android.widget.LinearLayout.LayoutParams(
                android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
                calculatedHeight
            );
            mergeListView.setLayoutParams(layoutParams);
        }

        // 初始设置列表高度
        updateListViewHeight();

    function showMultiLineInputDialog(title, callback) {
        try {
            var builder = new android.app.AlertDialog.Builder(ctx);
            builder.setTitle(title);

            var input = new android.widget.EditText(ctx);
            // 设置多行输入
            input.setInputType(android.text.InputType.TYPE_CLASS_TEXT | android.text.InputType.TYPE_TEXT_FLAG_MULTI_LINE);
            input.setSingleLine(false);
            input.setLines(8); // 默认8行
            input.setMaxLines(15); // 最大15行

            builder.setView(input);

            builder.setPositiveButton("确定", new android.content.DialogInterface.OnClickListener({
                onClick: function(dialog, which) {
                    var inputText = input.getText().toString();
                    if (callback) {
                        callback(inputText);
                    }
                }
            }));

            builder.setNegativeButton("取消", new android.content.DialogInterface.OnClickListener({
                onClick: function(dialog, which) {
                    dialog.cancel();
                }
            }));

            var dialog = builder.create();
            dialog.show();

        } catch (e) {
            console.error("显示多行输入对话框失败: " + e.toString());
            // 降级为单行输入
            showInputDialog(title + " (使用单行输入)", callback);
        }
    }

  // 新增：修改角色函数（预填原有数据，流程：改角色名→改别名→改发音人）
    function doEditCharacterOperation(position) {
        if (position < 0 || position >= characterRecords.length) {
            Toast.makeText(ctx, "角色索引无效", Toast.LENGTH_SHORT).show();
            return;
        }
        var targetChar = characterRecords[position];
        var originalName = targetChar.name || "";
        var originalAlias = targetChar.aliases || "";

        showInputDialog("修改角色名（原：" + originalName + "）", function(newName) {
            var finalName = newName ? newName.trim() : "";
            if (finalName === "") {
                Toast.makeText(ctx, "角色名不能为空", Toast.LENGTH_SHORT).show();
                return;
            }

            var aliasDefault = originalAlias || originalName;
            showInputDialog("修改角色别名（原：" + aliasDefault + "）", function(newAlias) {
                var finalAlias = newAlias ? newAlias.trim() : "";
                finalAlias = finalAlias || finalName;

                targetChar.name = finalName;
                targetChar.aliases = finalAlias;

                saveCharacterData();
                createGengxinFile();
                refreshCharacterList();

                Toast.makeText(ctx, "角色修改成功：" + finalName, Toast.LENGTH_SHORT).show();
            }, aliasDefault);
        }, originalName);
    }

